import { h, render, Component, Fragment } from 'preact';
import { useState, useCallback, useRef } from 'preact/hooks';
import { configs } from './configs';
import style from './css/dropdown'

class FontSizeDialog extends Component {
	
	upSize = () => {		
		var $curSize = parseInt($('#content').css('font-size'))
        var $newSize = $curSize + 2;
	
         $('#content').css('font-size', $newSize + 'px');
         var $newLineHeight = parseInt($('#content').css('line-height')) + 2;        
         $('#content').css('line-height', $newLineHeight + 'px');
		 var $curFnSize = parseInt($('#fnglo-wrapper').css('font-size'))

		 $('.mdl-card__supporting-text').css('font-size', $newSize + 'px');
		 $('.mdl-card__supporting-text').css('line-height', $newLineHeight + 'px');
	}
	
	downSize = () => {
		var $curSize = parseInt($('#content').css('font-size'));
        var $newSize = $curSize - 2;
        $('#content').css('font-size', $newSize + 'px');
        var $newLineHeight = parseInt($('#content').css('line-height')) - 2;        
        $('#content').css('line-height', $newLineHeight + 'px');
		$('.mdl-card__supporting-text').css('font-size', $newSize + 'px');
		 $('.mdl-card__supporting-text').css('line-height', $newLineHeight + 'px');
	}
	
	showDialog = () => {
		//var dialog = document.querySelector('#font-size-dialog');
		console.log(this.scrollingDlg);
		if(!this.scrollingDlg.showModal) {
			dialogPolyfill.registerDialog(this.scrollingDlg);
		}
		this.scrollingDlg.showModal();
	}
	
	closeDialog = () => {this.scrollingDlg.close()}

		
	render() {
		return (
			<dialog class="mdl-dialog" id="font-size-dialog" ref={scrollingDlg => {this.scrollingDlg = scrollingDlg;}}>
			   <h4 class="mdl-dialog__title">{configs.change_font}</h4>
			   <div class="mdl-dialog__actions">
				<button class="close mdl-button" 
				id="close-font-size-dialog" 
				onclick={this.closeDialog}>{configs.close}</button>
				<button class="mdl-button" 
				id="increase-font-size" 
				onclick={this.upSize}>+</button>
				<button class="mdl-button" 
				id="decrease-font-size" 
				onclick={this.downSize}>-</button>
				</div>
			</dialog>
		)
	}
}


function HeaderMenu(props) {
	
	const dialog = useRef(null);
	const showFontDialog = () => dialog.current.showDialog();
	
	const onMenuClick = () => {
		document.getElementById('myDropdown').classList.toggle('show');
	};

	window.onclick = (e) => {
		if (!e.target.matches('.dropbtn')) {
			var dropdowns = document.getElementsByClassName('dropdown-content');
			var i;
			for (i = 0; i < dropdowns.length; i++){
				var openDropdown = dropdowns[i];
				if (openDropdown.classList.contains('show')){
					openDropdown.classList.remove('show');
				}
			}
		}
	};

	return (
		<Fragment>
		<div class="dropdown">
			<span onclick={onMenuClick} class="dropbtn material-icons">more_vert</span>						
			<div id="myDropdown" class="dropdown-content">
				<a onclick={showFontDialog}>{configs.change_font}</a>
			</div>
		</div> 
		<FontSizeDialog ref={dialog}/>
		</Fragment>
	);
}

function BookSelector(props) {
	const popUp = useRef(null);

	const hideMenu = () => {
		if (popUp.current) {
			popUp.current.style.visibility = 'hidden';
			document.removeEventListener('click', hideOnClick);
			popUp.current.dataset.shown = false;
		}
	};

	const hideOnClick = (event) => {
		var el1 = event.target.closest('#book-menu');
		var el2 = event.target.closest('#book-selector');
		if (!el1 && !el2) {
			hideMenu();
		}
	};

	const toggleBookMenu = () => {
		console.log("book menu clicked");
		if (popUp.current && props.toolbar.current && popUp.current.style.visibility == 'hidden'){
			var pop = popUp.current;
			var rect = props.toolbar.current.getBoundingClientRect();
			var scrollTop = window.scrollTop;
			pop.style.top = rect.top + rect.height + scrollTop + "px";
			pop.style.left = "12.5%";
			pop.style.right = "12.5%";
			pop.style.width = "70%";//200 + "px";
			pop.style.maxHeight = 400 + "px";
			pop.style.visibility = "visible";
			pop.dataset.shown = true;
			document.addEventListener('click', hideOnClick );
			document.addEventListener('scroll', () => {
				hideMenu();
			});	
		} 
	};

	const handleMenuClick = (book) => {
		hideMenu();
		props.updateBook(book);
	};

	return (
		<Fragment>
			<div id="book-menu" ref={popUp} style="visibility:hidden;">
			{props.books.map(item =>
			<Fragment key={item.name}>
				<div class='intro-menu-item'>
					<a onclick={() => handleMenuClick(item)}>{item.name}</a>
				</div>
			</Fragment>
			)}
			</div>
			<span id="book-selector">
				<span 
				id="book-selector-a" 
				onclick={toggleBookMenu}>{props.curName}</span>
			</span>
		</Fragment>
	);
}


function ChapterSelector(props){
	const popUp = useRef(null);

	const hideChapterMenu = () => {
		if (popUp.current) {
			popUp.current.style.visibility = 'hidden';
			document.removeEventListener('click', hideOnClick);
			popUp.current.dataset.shown = false;
		}
	};

	const hideOnClick = (event) => {
		var el1 = event.target.closest('#chapter-menu');
		var el2 = event.target.closest('#chapter-selector');
		if (!el1 && !el2) {
			hideChapterMenu();
		}
	};

	const toggleChapterMenu = () => {
		if (popUp.current && props.toolbar.current && popUp.current.style.visibility == 'hidden'){
			var pop = popUp.current;
			var rect = props.toolbar.current.getBoundingClientRect();
			var scrollTop = window.scrollTop;
			pop.style.top = rect.top + rect.height + scrollTop + "px";
			pop.style.left = "12.5%";
			pop.style.right = "12.5%";
			pop.style.width = "70%";//200 + "px";
			pop.style.maxHeight = 400 + "px";
			pop.style.visibility = "visible";
			pop.dataset.shown = true;
			document.addEventListener('click', hideOnClick );
			document.addEventListener('scroll', () => {
				hideChapterMenu();
			});	
		} 
	};

	const nav = (newAddress, cptNum) => {
		props.requestCptNav(newAddress, cptNum);
		hideChapterMenu();
	};

	//class="chapter-table-wrapper" class="chapter-menu-item"

	const buildCptMenuItem = (item) => {
		if (item.cid.includes('PENGANTAR')) {
			return (
				<div class="mdl-cell mdl-cell--4-col mdl-cell-top chapter-menu-item">
					<a onclick={() => nav(item.cid, item.number)}>{item.number}</a>
				</div>
			);
		}
		return (
			<div class="mdl-cell mdl-cell--1-col chapter-menu-item">
				<a onclick={() => nav(item.cid, item.number)}>{item.number}</a>
			</div>
		);
	};

	return (
		<Fragment>
			<div id="chapter-menu" style="visibility:hidden;" ref={popUp} shown={false}>
				<div  class="mdl-grid">
					{props.chapters.map(buildCptMenuItem)}
				</div>
			</div>
			<span id="chapter-selector">
				<span href="#" 
				id="chapter-selector-a" 
				onclick={toggleChapterMenu}>{props.curChapter}</span>
			</span>
		</Fragment>
	)
}

export function PageHeader(props) {	
	const toolbar = useRef(null);
	return (
		<header class="mdl-layout__header"  id="header-bar" ref={toolbar}>
				<div class="navigation-top">
					<img src="icons/icon-36.png" id="nav-app-icon"></img>
					<BookSelector 
						books={props.books} 
						toolbar={toolbar} 
						curName={props.bookName}
						updateBook={props.updateBook}/>
					<ChapterSelector 
						requestCptNav={props.requestCptNav}
						chapters={props.chapters} 
						toolbar={toolbar}
						curChapter={props.curChapter}/>
					<HeaderMenu />
				</div>
		</header>
	);
	
}

